INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (1, '2026-04-07', NULL, '中国', 'policy', '证监会《短线交易监管规定》正式实施', 3, NULL, NULL, NULL, NULL, '证监会即将发布新的《短线交易监管规定》，请问这项政策主要针对哪些市场行为？市场预期对高频交易有何影响？可能影响哪些A股板块如券商、金融科技等？如果政策比预期更严格，会怎样？投资者应重点关注什么？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (2, '2026-04-15', NULL, '中国', 'policy', '深市主板一季报预告强制披露截止', 2, NULL, NULL, NULL, NULL, '4月15日是深市主板一季度业绩预告强制披露的最后期限，请问目前市场对此有何预期？可能会影响哪些板块例如制造业、科技等？如果多数公司业绩超出或低于预期，将如何影响股市？投资者应该关注哪些关键指标？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (3, '2026-04-30', NULL, '中国', 'policy', '2025年报+2026一季报全部披露完毕', 2, NULL, NULL, NULL, NULL, '到4月底，所有上市公司需完成2025年年报及2026年一季度报告的披露，请分析当前市场对企业盈利状况的预期。哪些行业或板块可能会受到特别关注？若整体表现超乎预期（好于/差于），市场反应将会如何？投资者最应该注意哪些信息？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (4, '2026-04-30', NULL, '美国', 'interest_rate', '美联储FOMC议息会议', 3, NULL, NULL, NULL, NULL, '2026年9月22日将举行另一场美联储FOMC会议，请评估：市场对此次会议的主要观点是什么？此决策对中国股市特别是外资持股较多的公司有何影响？如果美联储态度突然转变，全球金融市场将如何响应？投资者应聚焦于哪些关键议题？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (5, '2026-05-01', NULL, '中国', 'other', '劳动节假期开始', 2, NULL, NULL, NULL, NULL, '中国即将迎来五一劳动节长假，请分析这对消费、旅游等相关行业的影响预期。预计哪些具体领域会受益最多？如果实际数据远超预期，股市反应如何？投资者在假期前后应注意观察哪些趋势？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
