INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (26, '2026-09-15', NULL, '中国', 'monetary', 'MLF/LPR利率公布日', 2, NULL, NULL, NULL, NULL, '2026年9月15日将同时公布MLF与LPR利率，请分析：市场对这两次利率调整有何预期？这些变化主要影响哪些A股领域比如银行、地产？假设MLF或LPR出现较大变动，其对整体经济及股市意味着什么？投资者需要注意哪些信号？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (27, '2026-09-20', NULL, '中国', 'monetary', 'LPR利率公布日', 2, NULL, NULL, NULL, NULL, '2026年9月20日再次迎来LPR利率公布，请考虑：这次LPR调整的市场预期是什么？它将如何作用于A股的不同板块特别是银行、建筑？如果最终结果偏离预期，可能会引起怎样的市场波动？投资者应该特别留心哪些因素？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (28, '2026-09-22', NULL, '美国', 'interest_rate', '美联储FOMC议息会议', 3, NULL, NULL, NULL, NULL, '2026年9月22日将举行另一场美联储FOMC会议，请评估：市场对此次会议的主要观点是什么？此决策对中国股市特别是外资持股较多的公司有何影响？如果美联储态度突然转变，全球金融市场将如何响应？投资者应聚焦于哪些关键议题？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
INSERT INTO `trade_calendar_event` (`id`, `event_date`, `event_time`, `country`, `category`, `title`, `importance`, `previous_value`, `forecast_value`, `actual_value`, `impact`, `ai_prompt`, `source`, `source_url`, `is_recurring`, `recurrence_rule`, `status`, `created_at`, `updated_at`) VALUES (29, '2026-10-01', NULL, '中国', 'other', '国庆节假期开始', 2, NULL, NULL, NULL, NULL, '2026年10月1日标志着国庆长假开始，请考察：历年国庆期间A股表现如何？旅游、零售等相关行业通常会有怎样的行情？长假前后投资者情绪一般会发生什么变化？面对即将到来的假期，投资者应该如何调整策略？', 'qwen_search', NULL, 0, NULL, 'upcoming', '2026-04-04 10:10:24', '2026-04-04 10:10:24');
